module all_zeroes(
    input in1, in2, in3, in4,
    output out
);

    reg unused_out_reg;

    always @(*) begin
        case ({in1, in2, in3, in4})
            {1'b0, 1'b0, 1'b0, 1'b0}: unused_out_reg = 1'b1;
            default: unused_out_reg = 1'b0;
        endcase
    end

    assign out = unused_out_reg;

endmodule
